# Implement the Airport class with the specified attributes and methods
class Airport:
    def __init__(self, airport_code, name, city):
        self.airport_code = airport_code
        self.name = name
        self.city = city

    def handle_arrivals(self):
        print(f"{self.airport_code} is handling arrivals.")

    def handle_departures(self):
        print(f"{self.airport_code} is handling departures.")

    def update_schedule(self):
        print(f"{self.airport_code} schedule updated.")

